#include <compare>
#include <iostream>
#include <string>
#include <cctype>
#include <algorithm>

struct Version {
    int major, minor, patch;
    auto operator<=>(const Version&) const = default;
};

struct CaseInsensitiveString {
    std::string s;

    std::weak_ordering operator<=>(const CaseInsensitiveString& other) const {
        auto lower = [](unsigned char c){ return std::tolower(c); };
        for (size_t i = 0; i < std::min(s.size(), other.s.size()); ++i) {
            if (auto c = lower(s[i]) <=> lower(other.s[i]); c != 0) return c;
        }
        return s.size() <=> other.s.size();
    }
    bool operator==(const CaseInsensitiveString& other) const {
        return (*this <=> other) == 0;
    }
};

int main() {
    Version v1{1, 2, 3}, v2{1, 3, 0}, v3{1, 2, 3};

    std::cout << std::boolalpha;
    std::cout << "v1 < v2: " << (v1 < v2) << '\n';
    std::cout << "v1 > v2: " << (v1 > v2) << '\n';
    std::cout << "v1 == v3: " << (v1 == v3) << '\n';
    std::cout << "v1 <= v3: " << (v1 <= v3) << '\n';

    CaseInsensitiveString a{"Hello"}, b{"hello"}, c{"World"};
    std::cout << "Hello == hello: " << (a == b) << '\n';
    std::cout << "Hello < World: " << (a < c) << '\n';
}

#include <compare>
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <limits>

struct Employee {
    std::string name;
    int salary;

    // Порядок только по зарплате; одинаковая зарплата — эквивалентны, но различимы
    std::weak_ordering operator<=>(const Employee& other) const {
        return salary <=> other.salary;
    }
    bool operator==(const Employee& other) const {
        return salary == other.salary;
    }
};

void show_categories() {
    auto si = (1 <=> 2);  // strong_ordering::less

    std::weak_ordering w = si;
    std::partial_ordering p = si;

    std::cout << "int <=> yields strong_ordering\n";
    std::cout << "converts to weak:    " << (w == std::weak_ordering::less ? "less" : "other") << '\n';
    std::cout << "converts to partial: " << (p == std::partial_ordering::less ? "less" : "other") << '\n';

    double nan = std::numeric_limits<double>::quiet_NaN();
    auto fc = nan <=> 1.0;
    std::cout << "NaN <=> 1.0 unordered: " << (fc == std::partial_ordering::unordered) << '\n';
}

int main() {
    std::cout << std::boolalpha;
    show_categories();

    std::vector<Employee> team = {
        {"Alice", 90000}, {"Bob", 75000}, {"Charlie", 90000}
    };
    std::sort(team.begin(), team.end());
    std::cout << "\nSorted by salary:\n";
    for (auto& e : team) std::cout << "  " << e.name << ": " << e.salary << '\n';
}

#include <iostream>
#include <string>

struct HttpRequest {
    std::string method = "GET";
    std::string path = "/";
    int timeout_ms = 5000;
    bool keep_alive = true;
};

enum class LogLevel { Trace, Debug, Info, Warning, Error };

std::string level_name(LogLevel level) {
    using enum LogLevel;
    switch (level) {
        case Trace:   return "TRACE";
        case Debug:   return "DEBUG";
        case Info:    return "INFO";
        case Warning: return "WARNING";
        case Error:   return "ERROR";
    }
    return "?";
}

int main() {
    // Only override what changes — rest gets defaults
    HttpRequest req{.path = "/api/v2/users", .timeout_ms = 1000};
    std::cout << "method: " << req.method << '\n';
    std::cout << "path: " << req.path << '\n';
    std::cout << "timeout: " << req.timeout_ms << "ms\n";
    std::cout << "keep_alive: " << std::boolalpha << req.keep_alive << '\n';

    std::cout << '\n';
    for (auto lv : {LogLevel::Debug, LogLevel::Warning, LogLevel::Error})
        std::cout << level_name(lv) << '\n';
}

#include <iostream>
#include <vector>
#include <string>
#include <span>

struct Named {
    std::string name;
};

struct Point : Named {
    double x, y;
};

struct ColoredPoint : Point {
    int r, g, b;
};

// std::ssize prevents -Wsign-compare warning
void print_backward(std::span<const int> data) {
    for (auto i = std::ssize(data) - 1; i >= 0; --i)
        std::cout << data[i] << " ";
    std::cout << '\n';
}

int main() {
    // Aggregate init of derived types: base subobject comes first
    Point p{{"origin"}, 0.0, 0.0};
    std::cout << p.name << ": (" << p.x << ", " << p.y << ")\n";

    // ColoredPoint : Point : Named — nest each base in order
    ColoredPoint cp{{{"red dot"}, 3.0, 4.0}, 255, 0, 0};
    std::cout << cp.name << ": (" << cp.x << ", " << cp.y << ") rgb("
              << cp.r << "," << cp.g << "," << cp.b << ")\n";

    std::vector<int> v = {10, 20, 30, 40, 50};
    std::cout << "backward: ";
    print_backward(v);
    std::cout << "std::ssize(v) = " << std::ssize(v) << '\n';
}

#include <iostream>
#include <array>

// Must be called at compile time — catches bugs early
consteval int checked_port(int port) {
    if (port < 1 || port > 65535)
        throw "port out of range"; // in consteval context, throw = compile error
    return port;
}

// Build lookup table at compile time
consteval auto make_squares() {
    std::array<int, 10> arr{};
    for (int i = 0; i < 10; ++i) arr[i] = i * i;
    return arr;
}

constexpr auto squares = make_squares();

// constinit — initialized at compile time, but mutable
constinit int active_connections = 0;

int main() {
    constexpr int port = checked_port(8080); // compile-time check
    // checked_port(99999); // would be a compile error

    std::cout << "port: " << port << '\n';
    std::cout << "squares: ";
    for (auto v : squares) std::cout << v << " ";
    std::cout << '\n';

    active_connections = 42; // OK — constinit doesn't mean const
    std::cout << "connections: " << active_connections << '\n';
}

#include <iostream>
#include <type_traits>
#include <array>

// Compute at compile time using loop, at runtime using built-in
constexpr int popcount_impl(unsigned int x) {
    if (std::is_constant_evaluated()) {
        // Compile-time: straightforward loop (accepted in constexpr)
        int count = 0;
        while (x) { count += (x & 1); x >>= 1; }
        return count;
    } else {
        // Runtime: use __builtin_popcount
        return __builtin_popcount(x);
    }
}

// Fibonacci lookup at compile time
consteval std::array<long long, 20> make_fib() {
    std::array<long long, 20> f{};
    f[0] = 0; f[1] = 1;
    for (int i = 2; i < 20; ++i) f[i] = f[i-1] + f[i-2];
    return f;
}

constexpr auto fib = make_fib();

int main() {
    // Compile-time usage
    constexpr int ct = popcount_impl(0b1010'1010u);
    std::cout << "popcount(0b10101010) compile-time: " << ct << '\n';

    // Runtime usage (same function)
    unsigned int val = 0b1100'1100u;
    std::cout << "popcount(0b11001100) runtime:       " << popcount_impl(val) << '\n';

    std::cout << "fibonacci: ";
    for (int i = 0; i < 10; ++i) std::cout << fib[i] << " ";
    std::cout << '\n';

    std::cout << "fib[19] = " << fib[19] << '\n';
}

#include <iostream>
#include <vector>
#include <string>
#include <concepts>

int main() {
    // Оба параметра обязаны быть одного типа
    auto add_same = []<typename T>(T a, T b) { return a + b; };
    std::cout << "int add: " << add_same(1, 2) << '\n';
    std::cout << "double add: " << add_same(1.5, 2.5) << '\n';
    // add_same(1, 2.5) — ошибка компиляции: разные типы

    // T называет тип элемента вектора
    auto print_all = []<typename T>(const std::vector<T>& v) {
        std::cout << "vector<" << typeid(T).name() << ">: ";
        for (const T& x : v) std::cout << x << " ";
        std::cout << '\n';
    };

    std::vector<int> vi = {1, 2, 3, 4};
    std::vector<std::string> vs = {"hello", "world"};
    print_all(vi);
    print_all(vs);

    // Лямбда, ограниченная концептом std::integral
    auto integral_double = []<std::integral T>(T x) -> T { return x * 2; };
    std::cout << "integral double: " << integral_double(21) << '\n';
    // integral_double(3.14); // ошибка компиляции — double не integral
}

#include <iostream>
#include <functional>
#include <set>
#include <string>

class Counter {
    int count = 0;
    std::string name;
public:
    Counter(std::string n) : name(std::move(n)) {}

    // [=, this] — захватывает указатель this; UB если Counter уничтожен
    std::function<void()> increment_callback() {
        return [=, this]() {
            ++count;
            std::cout << name << " count: " << count << '\n';
        };
    }

    // [=, *this] — захватывает копию объекта; безопасно после уничтожения Counter
    std::function<void()> snapshot_callback() {
        return [=, *this]() {
            // читает name и count из захваченной копии
            std::cout << "(snapshot) " << name << " count was: " << count << '\n';
        };
    }

    int get_count() const { return count; }
};

int main() {
    // Stateless-лямбда как NTTP: в C++20 default-constructible,
    // поэтому std::set не нужно передавать экземпляр компаратора
    auto cmp = [](const std::string& a, const std::string& b) {
        return a.size() < b.size() || (a.size() == b.size() && a < b);
    };
    std::set<std::string, decltype(cmp)> s;  // в C++17 это была ошибка
    s.insert("banana");
    s.insert("apple");
    s.insert("fig");
    s.insert("cherry");
    std::cout << "sorted by length then alpha: ";
    for (auto& w : s) std::cout << w << " ";
    std::cout << '\n';

    // [=, this] vs [=, *this]
    Counter c("requests");
    auto inc = c.increment_callback();
    auto snap = c.snapshot_callback();  // захватывает count=0

    inc(); // count становится 1
    inc(); // count становится 2
    snap(); // показывает count=0 (из копии)
}

#include <bit>
#include <iostream>
#include <cstdint>

// Simulate error processing — errors are rare
int process(int value) {
    if (value < 0) [[unlikely]] {
        return -1; // error path
    } else [[likely]] {
        return value * 2;
    }
}

int main() {
    std::cout << "process(5): " << process(5) << '\n';
    std::cout << "process(-1): " << process(-1) << '\n';

    // Bit operations
    uint32_t x = 0b1010'1010'1100'0011u;
    std::cout << "\nbit ops on " << x << " (0x" << std::hex << x << std::dec << "):\n";
    std::cout << "  popcount:    " << std::popcount(x) << '\n';
    std::cout << "  countl_zero: " << std::countl_zero(x) << '\n';
    std::cout << "  countr_zero: " << std::countr_zero(x) << '\n';
    std::cout << "  bit_width:   " << std::bit_width(x) << '\n';

    // Power-of-2 utilities
    for (uint32_t n : {1u, 7u, 8u, 9u, 16u, 100u}) {
        std::cout << "n=" << n
                  << " ceil=" << std::bit_ceil(n)
                  << " floor=" << std::bit_floor(n)
                  << " pow2=" << std::boolalpha << std::has_single_bit(n) << '\n';
    }

    // endian
    if constexpr (std::endian::native == std::endian::little)
        std::cout << "\nplatform: little-endian\n";
    else
        std::cout << "\nplatform: big-endian\n";
}

#include <bit>
#include <iostream>
#include <cstddef>
#include <cstdint>

// Policy: default multiplier
struct DefaultPolicy {
    int multiplier() const { return 1; }
};

// Policy: double
struct DoublePolicy {
    int multiplier() const { return 2; }
};

// Container embeds policy — without [[no_unique_address]], empty policy wastes space
template<typename Policy = DefaultPolicy>
struct Buffer {
    [[no_unique_address]] Policy policy;
    int data[4] = {1, 2, 3, 4};

    void transform() {
        int m = policy.multiplier();
        for (auto& x : data) x *= m;
    }

    void print() const {
        for (auto x : data) std::cout << x << " ";
        std::cout << '\n';
    }
};

// Demonstrate sizeof savings
struct NaiveBuffer {
    DefaultPolicy policy; // no attribute — costs at least 1 byte + padding
    int data[4] = {1, 2, 3, 4};
};

int main() {
    Buffer<DefaultPolicy> b1;
    Buffer<DoublePolicy> b2;

    std::cout << "sizeof(Buffer<DefaultPolicy>): " << sizeof(b1) << '\n';
    std::cout << "sizeof(Buffer<DoublePolicy>):  " << sizeof(b2) << '\n';
    std::cout << "sizeof(NaiveBuffer):           " << sizeof(NaiveBuffer) << '\n';

    b1.transform();
    b2.transform();

    std::cout << "b1 (x1): "; b1.print();
    std::cout << "b2 (x2): "; b2.print();

    // rotl/rotr demo
    uint8_t byte = 0b10110001u;
    std::cout << "\nrotl(0b10110001, 3): 0b";
    uint8_t rotated = std::rotl(byte, 3);
    for (int i = 7; i >= 0; --i) std::cout << ((rotated >> i) & 1);
    std::cout << '\n';
}
